inline std::vector<double> astarGridPath(std::vector<double> grid, double w, double h, double sx, double sy, double gx, double gy, double blockedAbove) { {int W=static_cast<int>(w),H=static_cast<int>(h);int Sx=static_cast<int>(sx),Sy=static_cast<int>(sy),Gx=static_cast<int>(gx),Gy=static_cast<int>(gy);if(W<=0||H<=0)return std::vector<double>{};auto in=[&](int x,int y){return x>=0&&y>=0&&x<W&&y<H;};if(!in(Sx,Sy)||!in(Gx,Gy))return std::vector<double>{};auto idx=[&](int x,int y){return y*W+x;};int N=W*H;std::vector<double> gScore(N,1e18);std::vector<int> came(N,-1);std::vector<char> closed(N,0);std::vector<int> open;open.reserve(256);auto blocked=[&](int x,int y){std::size_t k=static_cast<std::size_t>(idx(x,y));return k>=grid.size()?true:(grid[k]>blockedAbove);};if(blocked(Sx,Sy)||blocked(Gx,Gy))return std::vector<double>{};auto hfun=[&](int x,int y){return (std::fabs(x-Gx)+std::fabs(y-Gy))*1.030000;};int s=idx(Sx,Sy),g=idx(Gx,Gy);gScore[s]=0;open.push_back(s);while(!open.empty()){int besti=0;double bestf=1e18;for(int oi=0;oi<(int)open.size();++oi){int n=open[(std::size_t)oi];int x=n%W,y=n/W;double f=gScore[(std::size_t)n]+hfun(x,y);if(f<bestf){bestf=f;besti=oi;}}int cur=open[(std::size_t)besti];open.erase(open.begin()+besti);if(cur==g)break;if(closed[(std::size_t)cur])continue;closed[(std::size_t)cur]=1;int cx=cur%W,cy=cur/W;const int dx[4]={1,-1,0,0};const int dy[4]={0,0,1,-1};for(int k=0;k<4;++k){int nx=cx+dx[k],ny=cy+dy[k];if(!in(nx,ny)||blocked(nx,ny))continue;int ni=idx(nx,ny);if(closed[(std::size_t)ni])continue;double tg=gScore[(std::size_t)cur]+1.0;if(tg<gScore[(std::size_t)ni]){gScore[(std::size_t)ni]=tg;came[(std::size_t)ni]=cur;open.push_back(ni);} }}if(came[(std::size_t)g]<0 && g!=s)return std::vector<double>{};std::vector<double> path;for(int v=g;v>=0;v=came[(std::size_t)v]){path.push_back((double)v);if(v==s)break;}std::reverse(path.begin(),path.end());return path;} }
