inline std::vector<double> simplifyGridPath(std::vector<double> path, double w) { {int W=static_cast<int>(w);if(W<=0||path.size()<=2)return path;auto ix=[&](double p){int v=(int)p;return v%W;};auto iy=[&](double p){int v=(int)p;return v/W;};std::vector<double> out;out.reserve(path.size());out.push_back(path[0]);int px=ix(path[0]),py=iy(path[0]);int lx=ix(path[1])-px,ly=iy(path[1])-py;auto sgn=[&](int v){return v>0?1:(v<0?-1:0);};lx=sgn(lx);ly=sgn(ly);for(std::size_t i=1;i+1<path.size();++i){int cx=ix(path[i]),cy=iy(path[i]);int nx=ix(path[i+1]),ny=iy(path[i+1]);int dx=sgn(nx-cx),dy=sgn(ny-cy);if(dx==lx && dy==ly){continue;}out.push_back(path[i]);lx=dx;ly=dy;px=cx;py=cy;}out.push_back(path.back());return out;} }
