inline std::vector<double> integratePos(std::vector<double> pos, std::vector<double> vel, double n, double dt) { {int N=static_cast<int>(n);double DT=dt;std::vector<double> out;if(N<=0)return out;out.resize((std::size_t)N*3);for(int i=0;i<N;++i){std::size_t k=(std::size_t)i*3;double px=k<pos.size()?pos[k]:0,py=k+1<pos.size()?pos[k+1]:0,pz=k+2<pos.size()?pos[k+2]:0;double vx=k<vel.size()?vel[k]:0,vy=k+1<vel.size()?vel[k+1]:0,vz=k+2<vel.size()?vel[k+2]:0;out[k]=px+vx*DT;out[k+1]=py+vy*DT;out[k+2]=pz+vz*DT;}return out;} }
inline std::vector<double> steerSeek(double px, double py, double pz, double tx, double ty, double tz, double maxSpeed) { {double dx=tx-px,dy=ty-py,dz=tz-pz;double l=std::sqrt(dx*dx+dy*dy+dz*dz);std::vector<double> v(3,0);if(l<1e-9)return v;double s=maxSpeed<=0?0:maxSpeed/l;v[0]=dx*s;v[1]=dy*s;v[2]=dz*s;return v;} }
inline std::vector<double> boidsVelStep(std::vector<double> pos, std::vector<double> vel, double n, double dt, double neighborDist, double sepDist, double maxSpeed) { {int N=static_cast<int>(n);double DT=dt;double nd=neighborDist;double sd=sepDist;if(N<=0)return std::vector<double>{};double nd2=nd*nd,sd2=sd*sd;std::vector<double> out((std::size_t)N*3,0);for(int i=0;i<N;++i){std::size_t ik=(std::size_t)i*3;double ix=ik<pos.size()?pos[ik]:0,iy=ik+1<pos.size()?pos[ik+1]:0,iz=ik+2<pos.size()?pos[ik+2]:0;double vx=ik<vel.size()?vel[ik]:0,vy=ik+1<vel.size()?vel[ik+1]:0,vz=ik+2<vel.size()?vel[ik+2]:0;double sepX=0,sepY=0,sepZ=0,cohX=0,cohY=0,cohZ=0,aliX=0,aliY=0,aliZ=0;int cnt=0;for(int j=0;j<N;++j){if(j==i)continue;std::size_t jk=(std::size_t)j*3;double jx=jk<pos.size()?pos[jk]:0,jy=jk+1<pos.size()?pos[jk+1]:0,jz=jk+2<pos.size()?pos[jk+2]:0;double dx=jx-ix,dy=jy-iy,dz=jz-iz;double d2=dx*dx+dy*dy+dz*dz;if(d2>0 && d2<=nd2){++cnt;cohX+=jx;cohY+=jy;cohZ+=jz;double jvx=jk<vel.size()?vel[jk]:0,jvy=jk+1<vel.size()?vel[jk+1]:0,jvz=jk+2<vel.size()?vel[jk+2]:0;aliX+=jvx;aliY+=jvy;aliZ+=jvz;if(d2<=sd2){double inv=1.0/std::max(1e-9,std::sqrt(d2));sepX-=dx*inv;sepY-=dy*inv;sepZ-=dz*inv;}}}if(cnt>0){double inv=1.0/cnt;cohX=(cohX*inv-ix);cohY=(cohY*inv-iy);cohZ=(cohZ*inv-iz);aliX=(aliX*inv-vx);aliY=(aliY*inv-vy);aliZ=(aliZ*inv-vz);} double ax=sepX*1.170000+cohX*0.650000+aliX*0.960000;double ay=sepY*1.170000+cohY*0.650000+aliY*0.960000;double az=sepZ*1.170000+cohZ*0.650000+aliZ*0.960000;vx+=ax*DT;vy+=ay*DT;vz+=az*DT;vx+=std::sin((double)i*12.9898)*0.023000*DT;vz+=std::cos((double)i*78.233)*0.023000*DT;double sp=std::sqrt(vx*vx+vy*vy+vz*vz);double ms=maxSpeed; if(ms>0 && sp>ms){double s=ms/sp;vx*=s;vy*=s;vz*=s;}out[ik]=vx;out[ik+1]=vy;out[ik+2]=vz;}return out;} }
